 14→function hitTest(modelPos, floor, annotationTolerance) {
 15→  // Hit test doors first (smaller targets, higher priority)
 16→  for (const door of floor.doors) {
 17→    const wall = floor.walls.find(w => w.id === door.wallId);
 18→    if (!wall) continue;
 19→    const info = doorOutlineOnWall(wall, door);
 20→    const poly = [info.p1, info.p2, info.p3, info.p4];
 21→    if (pointInPolygon(modelPos, poly)) {
 22→      return { id: door.id, type: 'door' };
 23→    }
 24→  }
 25→
 26→  // Hit test windows
 27→  for (const win of floor.windows) {
 28→    const wall = floor.walls.find(w => w.id === win.wallId);
 29→    if (!wall) continue;
 30→    const info = windowOutlineOnWall(wall, win);
 31→    const poly = [info.p1, info.p2, info.p3, info.p4];
 32→    if (pointInPolygon(modelPos, poly)) {
 33→      return { id: win.id, type: 'window' };
 34→    }
 35→  }
 36→
 37→  // Hit test walls
 38→  // Hit test columns
 39→  for (const sc of (floor.sectionCuts || [])) {
 40→    if (hitTestSectionCut(modelPos, sc, annotationTolerance)) {
 41→      return { id: sc.id, type: 'sectionCut' };
 42→    }
 43→  }
 44→
 45→  for (const column of (floor.columns || [])) {
 46→    const outline = columnOutline(column);
 47→    if (pointInPolygon(modelPos, outline)) {
 48→      return { id: column.id, type: 'column' };
 49→    }
 50→  }
 51→
 52→  // Hit test beams
 53→  for (const beam of (floor.beams || [])) {
 54→    const renderData = getBeamRenderData(beam, floor.columns || []);
 55→    if (!renderData) continue;
 56→    if (pointInPolygon(modelPos, renderData.outline)) {
 57→      return { id: beam.id, type: 'beam' };
 58→    }
 59→  }
 60→
 61→  // Hit test walls
 62→  for (const wall of floor.walls) {
 63→    const outline = getWallRenderData(wall, floor.columns || []).outline;
 64→    if (pointInPolygon(modelPos, outline)) {
 65→      return { id: wall.id, type: 'wall' };
 66→    }
 67→  }
 68→
 69→  // Hit test stairs after walls/beams/columns so current editing priority stays intact.
 70→  for (const stair of (floor.stairs || [])) {
 71→    const renderData = getStairRenderData(stair);
 72→    if (!renderData) continue;
 73→    if (pointInPolygon(modelPos, renderData.outline)) {
 74→      return { id: stair.id, type: 'stair' };
 75→    }
 76→  }
 77→
 78→  // Hit test rooms (lowest priority)
 79→  for (const room of floor.rooms) {
 80→    if (room.points?.length >= 3 && pointInPolygon(modelPos, room.points)) {
 81→      return { id: room.id, type: 'room' };
 82→    }
 83→  }
 84→
 85→  if (floor.slab && slabContainsPoint(floor.slab, modelPos)) {
 86→    return { id: floor.slab.id, type: 'slab' };
 87→  }
 88→
 89→  const annotationHit = hitTestAnnotation(modelPos, floor, annotationTolerance);
 90→  if (annotationHit) {
 91→    return annotationHit;
 92→  }
 93→
 94→  return null;
 95→}
